result = {
    "batchIndex": 0,
    "translations": {}
}

missing = []
for item in batch:
    orig = item["original"]
    if orig in mapping:
        m = mapping[orig]
        result["translations"][orig] = {
            "key": m["key"],
            "pt": orig,
            "en": m["en"],
            "es": m["es"]
        }
    else:
        missing.append(orig)

if missing:
    print("MISSING strings:", len(missing))
    for s in missing:
        print(repr(s))
    raise SystemExit(1)

os.makedirs("tmp/translations", exist_ok=True)
with open("tmp/translations/batch-0-translated.json", "w", encoding="utf-8") as f:
    json.dump(result, f, ensure_ascii=False, indent=2)

print("Done. Wrote", len(result["translations"]), "translations.")
